import bisect
from typing import List

class Solution:
    def kIncreasing(self, arr: List[int], k: int) -> int:
        total = 0
        for s in range(k):
            group = arr[s::k]
            tails = []
            for num in group:
                idx = bisect.bisect_right(tails, num)
                if idx == len(tails):
                    tails.append(num)
                else:
                    tails[idx] = num
            total += len(group) - len(tails)
        return total
